import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONObject;
import lombok.extern.slf4j.Slf4j;
import org.apache.http.HttpResponse;
import org.apache.http.util.EntityUtils;
import org.springframework.util.StringUtils;

import java.util.HashMap;
import java.util.Map;

@Slf4j
public class ImportPdfUtil {

    private static final String HOST = "https://ali.duhuitech.com";
    private static final String PATH = "/v1/convert";
    private static final String CODE = "APPCODE ";

    public static String word2Pdf(String appcode, String filePath, String fileName, String type) {
        Map<String, String> headers = new HashMap<>();
        headers.put("Authorization", CODE + appcode);
        Map<String, String> querys = new HashMap<>();
        querys.put("url", filePath + fileName);
        querys.put("type", type);
        querys.put("linearization", "0");
        querys.put("pdffilename", fileName.replace("." + type, ""));

        try {
            JSONObject result = null;
            HttpResponse response = HttpUtils.doGet(HOST, PATH, headers, querys);
            JSONObject jsonResponse = JSON.parseObject(EntityUtils.toString(response.getEntity()));
            if (null == jsonResponse || StringUtils.isEmpty(jsonResponse.get("code"))) {
                return "未知异常";
            }
            String code = jsonResponse.get("code").toString();
            if ("40002".equals(code)) {
                return "参数不符合规范";
            } else if ("40001".equals(code)) {
                return "参数错误";
            } else if ("40000".equals(code)) {
                return "通用错误";
            } else if ("10000".equals(code)) {
                result = jsonResponse.getJSONObject("result");
            } else {
                return "未知异常";
            }
            if (null == result || StringUtils.isEmpty(result.getString("token"))) {
                return "未知异常";
            }
            String token = result.getString("token");
            return PdfConversionChecker.getPdf(token);
        } catch (Exception e) {
            log.error("word2Pdf异常：{}", e.getMessage());
            e.printStackTrace();
        }
        return "未知异常";
    }
}

