import com.alibaba.fastjson.JSON;
import com.alibaba.fastjson.JSONObject;
import lombok.extern.slf4j.Slf4j;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;
import java.util.concurrent.*;

@Slf4j
public class PdfConversionChecker {

    private static final String QUERY_URL = "https://api.duhuitech.com/q?token=";

    public static String getPdf(String token) {

        CompletableFuture<String> future = new CompletableFuture<>();
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
        Runnable task = () -> {
            try {
                int i = 1;
                log.info("开始执行轮询请求度慧方法第{}次开始，token={}", i, token);
                HttpURLConnection connection = (HttpURLConnection) new URL(QUERY_URL + token).openConnection();
                connection.setRequestMethod("GET");
                int responseCode = connection.getResponseCode();
                if (responseCode == HttpURLConnection.HTTP_OK) {
                    BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream()));
                    String inputLine;
                    StringBuilder response = new StringBuilder();
                    try {
                        while ((inputLine = in.readLine()) != null) {
                            response.append(inputLine);
                        }
                    } finally {
                        if (null != in) {
                            in.close();
                        }
                    }
                    // 解析响应
                    String jsonResponse = response.toString();
                    log.info("轮询请求度慧方法第{}次响应={}", i, jsonResponse);
                    i = i++;
                    // 检查状态
                    if (jsonResponse.contains("\"status\":\"Done\"")) {
                        JSONObject jsonObject = JSON.parseObject(jsonResponse);
                        JSONObject result = (JSONObject) jsonObject.get("result");
                        String pdfurl = result.getString("pdfurl");
                        log.info("轮询请求度慧方法获取到pdfurl={}", pdfurl);
                        future.complete(pdfurl);
                        scheduler.shutdown();
                        log.info("scheduler.shutdown();");
                    } else if (jsonResponse.contains("\"status\":\"Failed\"")) {
                        future.completeExceptionally(new RuntimeException("PDF conversion failed."));
                        scheduler.shutdown();
                        log.info("scheduler.shutdown();");
                    }
                } else {
                    System.out.println("GET request not worked");
                }
            } catch (Exception e) {
                e.printStackTrace();
            }
        };
        // 每2秒执行一次任务
        scheduler.scheduleAtFixedRate(task, 0, 2, TimeUnit.SECONDS);
        try {
            // 等待结果
            return future.get();
        } catch (InterruptedException | ExecutionException e) {
            log.error("轮询请求度慧方法异常token={}，Exception={}", token, e.getMessage());
            throw new RuntimeException("Error getting PDF URL", e);
        }
    }
}

