                            // 可选，下载并保存PDF到本地路径
                            FileU.urlToFile1(pdfUrl, newfilePath, currentFileName.replace(fileType, "pdf"));
                        }, executor).exceptionally(e -> {
                            failReport.add(currentFileName);
                            downloadFailNum++;
                            e.printStackTrace();
                            return null;
                        });

                        futures.add(future);
                    }
                }
            }

            CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();

            FileOutputStream fos1 = new FileOutputStream(new File(publicPath + "Report_Data_" + startDate + ".zip"));
            ZipUtils.toZip(new File(publicPath + projectName + "_" + now + "_" + repCount), fos1, true);
            url = publicPath + "Report_Data_" + startDate + ".zip";

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    Map<String, Object> map = new HashMap<>();
    map.put(Constants.RESULT, domainName + url);
    map.put("failReport", failReport);
    return Result.success(map);
}
